import React, { useCallback, useMemo, useRef } from 'react';
import { 
  ReactFlow, 
  Background, 
  Controls, 
  ReactFlowProvider,
  useReactFlow
} from '@xyflow/react';
import { useShallow } from 'zustand/react/shallow';
import '@xyflow/react/dist/style.css';

import { useGraphStore } from '../../core/store/useGraphStore';
import { useViewStore } from '../../core/store/useViewStore';
import { useClipboard } from '../../core/hooks/useClipboard';
import { useBranchColors } from '../../core/hooks/useBranchColors';
import { CustomNodeWrapper } from './CustomNodeWrapper';
import { CustomEdge } from './CustomEdge';

const nodeTypes = {
  custom: CustomNodeWrapper
};

const edgeTypes = {
  custom: CustomEdge
};

const FlowCanvasContent: React.FC = () => {
  const reactFlowWrapper = useRef<HTMLDivElement>(null);
  const { screenToFlowPosition } = useReactFlow();
  
  const { 
    nodes, 
    edges, 
    onNodesChange, 
    onEdgesChange, 
    onConnect,
    addNode,
    executionResult
  } = useGraphStore(
    useShallow((state) => ({
      nodes: state.nodes,
      edges: state.edges,
      onNodesChange: state.onNodesChange,
      onEdgesChange: state.onEdgesChange,
      onConnect: state.onConnect,
      addNode: state.addNode,
      executionResult: state.executionResult
    }))
  );

  const { isResultsPanelExpanded } = useViewStore();

  useClipboard();

  const branchColorMap = useBranchColors(nodes, edges);

  // Edges that "won" a merge: for every sibling_fan_in advisory, mark the
  // edge from winner_input -> advisory.node_id so the canvas can highlight
  // which branch's values survived the last-wins / first-wins tiebreak.
  const winnerEdgeIds = useMemo(() => {
    const ids = new Set<string>();
    const warnings = executionResult?.merge_warnings ?? [];
    for (const w of warnings) {
      if (!w.winner_input || !w.node_id) continue;
      const edge = edges.find(
        (e) => e.source === w.winner_input && e.target === w.node_id
      );
      if (edge) ids.add(edge.id);
    }
    return ids;
  }, [edges, executionResult]);

  const coloredEdges = useMemo(() => {
    return edges.map(edge => {
      const info = branchColorMap.get(edge.id);
      const isMergeWinner = winnerEdgeIds.has(edge.id);
      if (info === undefined && !isMergeWinner) return edge;
      return {
        ...edge,
        data: {
          ...edge.data,
          branchColor: info?.color,
          branchLabel: info?.label,
          branchShared: info?.shared,
          isMergeWinner,
        },
      };
    });
  }, [edges, branchColorMap, winnerEdgeIds]);

  const onDragOver = useCallback((event: React.DragEvent) => {
    event.preventDefault();
    event.dataTransfer.dropEffect = 'move';
  }, []);

  const onDrop = useCallback(
    (event: React.DragEvent) => {
      event.preventDefault();

      const type = event.dataTransfer.getData('application/reactflow');

      // check if the dropped element is valid
      if (typeof type === 'undefined' || !type) {
        return;
      }

      const position = screenToFlowPosition({
        x: event.clientX,
        y: event.clientY,
      });

      addNode(type, position);
    },
    [screenToFlowPosition, addNode],
  );

  return (
    <div 
      className="w-full h-full outline-none" 
      ref={reactFlowWrapper}
      tabIndex={0} // Make the container focusable to capture key events
    >
      <ReactFlow
        nodes={nodes}
        edges={coloredEdges}
        onNodesChange={onNodesChange}
        onEdgesChange={onEdgesChange}
        onConnect={onConnect}
        nodeTypes={nodeTypes}
        onDragOver={onDragOver}
        onDrop={onDrop}
        fitView
        proOptions={{ hideAttribution: true }}
        defaultEdgeOptions={{
          type: 'custom',
          style: { 
            stroke: 'url(#edge-gradient)', 
            strokeWidth: 3,
            strokeDasharray: '8 6',
            filter: 'url(#glow)'
          },
          animated: true,
        }}
        edgeTypes={edgeTypes}
        deleteKeyCode={['Backspace', 'Delete']}
      >
        <svg style={{ position: 'absolute', top: 0, left: 0, width: 0, height: 0, pointerEvents: 'none' }}>
          <defs>
            <linearGradient id="edge-gradient">
              <stop offset="0%" stopColor="#38bdf8" />
              <stop offset="50%" stopColor="#6366f1" />
              <stop offset="100%" stopColor="#a855f7" />
            </linearGradient>
            <filter id="glow" x="-50%" y="-50%" width="200%" height="200%">
              <feGaussianBlur stdDeviation="3" result="coloredBlur"/>
              <feMerge>
                <feMergeNode in="coloredBlur"/>
                <feMergeNode in="SourceGraphic"/>
              </feMerge>
            </filter>
          </defs>
        </svg>
        <Background />
        <Controls 
          position="bottom-left" 
          style={
            (executionResult && !isResultsPanelExpanded) 
              ? { marginBottom: '40px', transition: 'margin-bottom 0.3s ease-in-out' } 
              : { transition: 'margin-bottom 0.3s ease-in-out' }
          }
        />
      </ReactFlow>
    </div>
  );
};

export const FlowCanvas: React.FC = () => {
  return (
    <ReactFlowProvider>
      <FlowCanvasContent />
    </ReactFlowProvider>
  );
};

import React, { useState } from 'react';
import { AlertCircle, ChevronDown, ChevronUp } from 'lucide-react';

interface AlertsSectionProps {
    alerts: any[];
}

export const AlertsSection: React.FC<AlertsSectionProps> = ({ alerts }) => {
    const [isExpanded, setIsExpanded] = useState(true);

    if (!alerts || alerts.length === 0) return null;

    return (
        <div className="bg-amber-50 dark:bg-amber-900/20 border border-amber-200 dark:border-amber-800 rounded-lg p-4">
            <div 
                className="flex justify-between items-center cursor-pointer"
                onClick={() => setIsExpanded(!isExpanded)}
            >
                <h3 className="font-medium text-amber-800 dark:text-amber-200 flex items-center">
                    <AlertCircle className="w-4 h-4 mr-2" />
                    Data Quality Alerts ({alerts.length})
                </h3>
                {isExpanded ? (
                    <ChevronUp className="w-4 h-4 text-amber-800 dark:text-amber-200" />
                ) : (
                    <ChevronDown className="w-4 h-4 text-amber-800 dark:text-amber-200" />
                )}
            </div>
            
            {isExpanded && (
                <div className="max-h-40 overflow-y-auto pr-2 mt-2 animate-in slide-in-from-top-2 duration-200">
                    <ul className="space-y-1">
                        {alerts.map((alert: any, i: number) => (
                            <li key={i} className="text-sm text-amber-700 dark:text-amber-300 flex items-start">
                                <span className="mr-2">•</span>
                                <span>
                                    {alert.column && <span className="font-semibold">{alert.column}: </span>}
                                    {alert.message}
                                </span>
                            </li>
                        ))}
                    </ul>
                </div>
            )}
        </div>
    );
};

import React, { useState, useEffect, useRef } from 'react';
import { EDAService, Filter } from '../../core/api/eda';
import { Plus, X, Loader2 } from 'lucide-react';

interface TreeItem {
    name: string;
    value: number;
    ratio: number;
}

interface TreeLevel {
    id: string;
    splitColumn: string | null; // The column used to generate this level's items
    items: TreeItem[];
    selectedItemName: string | null;
    filters: Filter[]; // Filters applied to reach this level
}

interface DecompositionTreeProps {
    datasetId: number;
    measureCol: string;
    measureAgg: string;
    columns: string[];
    initialFilters: Filter[];
}

// Module-level cache to persist state across tab switches
const treeCache: Record<string, { levels: TreeLevel[], splitPath: (string|null)[] }> = {};

export const DecompositionTree: React.FC<DecompositionTreeProps> = ({
    datasetId,
    measureCol,
    measureAgg,
    columns,
    initialFilters
}) => {
    const [levels, setLevels] = useState<TreeLevel[]>([]);
    const [loading, setLoading] = useState(false);
    const [splitMenuOpen, setSplitMenuOpen] = useState<{ levelIndex: number, item: TreeItem, x: number, y: number } | null>(null);
    
    // We need to store the "structure" of the tree (the sequence of split columns)
    // so we can automatically refresh subsequent levels when a parent selection changes.
    const [splitPath, setSplitPath] = useState<(string | null)[]>([null]); // Root is null

    const containerRef = useRef<HTMLDivElement>(null);
    const innerRef = useRef<HTMLDivElement>(null);
    const [paths, setPaths] = useState<{ d: string }[]>([]);

    // Auto-scroll to right when levels change
    useEffect(() => {
        if (containerRef.current) {
            containerRef.current.scrollTo({ left: containerRef.current.scrollWidth, behavior: 'smooth' });
        }
    }, [levels.length]);

    const updatePaths = () => {
        if (!innerRef.current) return;

        const newPaths: { d: string }[] = [];
        const innerRect = innerRef.current.getBoundingClientRect();

        levels.forEach((level, index) => {
            if (index >= levels.length - 1) return;
            
            const selectedItemName = level.selectedItemName;
            if (!selectedItemName) return;

            const startId = `node-${index}-${selectedItemName}`;
            const startEl = document.getElementById(startId);

            if (startEl) {
                const startRect = startEl.getBoundingClientRect();
                
                // Calculate start point (right side of selected item)
                const x1 = startRect.right - innerRect.left;
                const y1 = startRect.top + (startRect.height / 2) - innerRect.top;
                
                // Determine end point
                let x2, y2;
                
                const nextLevel = levels[index + 1];
                if (nextLevel.selectedItemName) {
                    // If next level has a selection, connect to that item
                    const endId = `node-${index + 1}-${nextLevel.selectedItemName}`;
                    const endEl = document.getElementById(endId);
                    
                    if (endEl) {
                        const endRect = endEl.getBoundingClientRect();
                        x2 = endRect.left - innerRect.left;
                        y2 = endRect.top + (endRect.height / 2) - innerRect.top;
                    } else {
                        // Fallback if element not found yet
                        return;
                    }
                } else {
                    // If no selection in next level, connect to the left-center of the list container
                    // We need an ID for the list container
                    const listId = `list-${index + 1}`;
                    const listEl = document.getElementById(listId);
                    
                    if (listEl) {
                        const listRect = listEl.getBoundingClientRect();
                        x2 = listRect.left - innerRect.left;
                        // Point to the vertical center of the visible list area, or just the top area?
                        // Let's point to the top-ish area so it looks like it feeds into the list
                        // Or maybe the center of the container height?
                        y2 = listRect.top + (listRect.height / 2) - innerRect.top;
                    } else {
                        return;
                    }
                }

                if (x2 !== undefined && y2 !== undefined) {
                    // Draw a sigmoid curve
                    const controlPointX = (x1 + x2) / 2;
                    const d = `M ${x1} ${y1} C ${controlPointX} ${y1}, ${controlPointX} ${y2}, ${x2} ${y2}`;
                    newPaths.push({ d });
                }
            }
        });

        setPaths(newPaths);
    };

    // Calculate connection paths
    React.useLayoutEffect(() => {
        updatePaths();
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [levels, splitMenuOpen]); // Recalculate when levels change or menu opens (layout might shift)

    // Update cache when state changes
    useEffect(() => {
        if (levels.length > 0) {
            const cacheKey = `${datasetId}-${measureCol}-${measureAgg}`;
            treeCache[cacheKey] = { levels, splitPath };
        }
    }, [levels, splitPath, datasetId, measureCol, measureAgg]);

    // Initialize Root or Load from Cache
    useEffect(() => {
        const cacheKey = `${datasetId}-${measureCol}-${measureAgg}`;
        if (treeCache[cacheKey]) {
            setLevels(treeCache[cacheKey].levels);
            setSplitPath(treeCache[cacheKey].splitPath);
        } else {
            loadRoot();
        }
    // eslint-disable-next-line react-hooks/exhaustive-deps
    }, [datasetId, measureCol, measureAgg]);

    const loadRoot = async () => {
        setLoading(true);
        try {
            const res = await EDAService.getDecomposition(
                datasetId,
                measureCol === 'count' ? null : measureCol,
                measureAgg,
                '',
                initialFilters
            );
            
            const rootLevel: TreeLevel = {
                id: 'root',
                splitColumn: null,
                items: res,
                selectedItemName: null,
                filters: initialFilters
            };
            
            setLevels([rootLevel]);
            setSplitPath([null]);
        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const handleHeaderSplitClick = (levelIndex: number, event: React.MouseEvent) => {
        // Only allow splitting if an item is selected in this level
        const level = levels[levelIndex];
        if (!level.selectedItemName) {
            // Maybe show a toast or tooltip? For now just return.
            return;
        }

        const item = level.items.find(i => i.name === level.selectedItemName);
        if (!item) return;

        // Open Split Menu
        const rect = (event.currentTarget as HTMLElement).getBoundingClientRect();
        const containerRect = containerRef.current?.getBoundingClientRect();
        
        if (containerRect) {
            let x = rect.right - containerRect.left + 10;
            let y = rect.top - containerRect.top;

            const wrapperWidth = containerRef.current?.parentElement?.clientWidth || window.innerWidth;
            if (x + 260 > wrapperWidth) {
                x = rect.left - containerRect.left - 270; 
            }

            const wrapperHeight = containerRef.current?.parentElement?.clientHeight || window.innerHeight;
            if (y + 300 > wrapperHeight) {
                y = wrapperHeight - 310;
            }

            setSplitMenuOpen({
                levelIndex,
                item,
                x,
                y
            });
        }
    };

    const handleItemClick = async (levelIndex: number, item: TreeItem) => {
        // 1. Update selection in current level
        const newLevels = [...levels];
        newLevels[levelIndex].selectedItemName = item.name;
        
        // Check if we have a next level defined in our split path
        const nextSplitCol = splitPath[levelIndex + 1];
        
        if (nextSplitCol) {
            // AUTOMATIC UPDATE: If next level exists, refresh it instead of opening menu
            setLoading(true);
            try {
                // Construct filters for the next level
                const currentLevel = newLevels[levelIndex];
                const newFilters = [...currentLevel.filters];
                if (currentLevel.splitColumn) {
                    newFilters.push({
                        column: currentLevel.splitColumn,
                        operator: '==',
                        value: item.name
                    });
                } else if (levelIndex === 0) {
                    // Root level
                }

                // Fetch data for next level
                const res = await EDAService.getDecomposition(
                    datasetId,
                    measureCol === 'count' ? null : measureCol,
                    measureAgg,
                    nextSplitCol,
                    newFilters
                );

                // Update next level
                const nextLevel: TreeLevel = {
                    id: `level-${levelIndex + 1}`,
                    splitColumn: nextSplitCol,
                    items: res,
                    selectedItemName: null, // Reset selection in next level
                    filters: newFilters
                };
                
                // Replace next level and remove any levels AFTER it (because selection in next level is reset)
                const finalLevels = [...newLevels.slice(0, levelIndex + 1), nextLevel];
                setLevels(finalLevels);
                
                // Update split path to match (remove anything after next level)
                // Actually, if we reset selection in next level, we lose the path after it.
                // So we should truncate splitPath too?
                // Yes, because if Level 2 selection is gone, Level 3 cannot exist.
                setSplitPath(splitPath.slice(0, levelIndex + 2));

            } catch (err) {
                console.error(err);
            } finally {
                setLoading(false);
            }
        } else {
            // No next level defined, just update selection
            setLevels(newLevels);
            // Do NOT open menu automatically anymore. User must click header + button.
        }
    };

    const handleSplit = async (column: string) => {
        if (!splitMenuOpen) return;
        
        const { levelIndex, item } = splitMenuOpen;
        setSplitMenuOpen(null);
        setLoading(true);

        try {
            const currentLevel = levels[levelIndex];
            const newFilters = [...currentLevel.filters];
            if (currentLevel.splitColumn) {
                newFilters.push({
                    column: currentLevel.splitColumn,
                    operator: '==',
                    value: item.name
                });
            }

            const res = await EDAService.getDecomposition(
                datasetId,
                measureCol === 'count' ? null : measureCol,
                measureAgg,
                column,
                newFilters
            );

            const newLevel: TreeLevel = {
                id: `level-${levelIndex + 1}`,
                splitColumn: column,
                items: res,
                selectedItemName: null,
                filters: newFilters
            };

            const newLevels = [...levels.slice(0, levelIndex + 1), newLevel];
            setLevels(newLevels);
            
            // Update Split Path
            const newSplitPath = [...splitPath.slice(0, levelIndex + 1), column];
            setSplitPath(newSplitPath);

        } catch (err) {
            console.error(err);
        } finally {
            setLoading(false);
        }
    };

    const closeSplit = (levelIndex: number) => {
        setLevels(levels.slice(0, levelIndex));
        setSplitPath(splitPath.slice(0, levelIndex)); 
    };

    return (
        <div className="relative w-full h-[600px] bg-slate-50 dark:bg-slate-900 overflow-hidden flex flex-col">
            {loading && (
                <div className="absolute top-2 right-2 z-50">
                    <Loader2 className="w-5 h-5 animate-spin text-blue-500" />
                </div>
            )}
            <div className="flex-1 overflow-x-auto overflow-y-hidden" ref={containerRef}>
                <div className="flex h-full p-8 min-w-max gap-12 relative" ref={innerRef}>
                    {levels.map((level, index) => (
                        <div key={index} className="flex flex-col w-[200px] h-full relative z-10">
                            {/* Header */}
                            <div 
                                id={`header-${index}`}
                                className="flex items-center justify-between mb-4 bg-white dark:bg-slate-800 p-2 rounded shadow-sm border border-slate-200 dark:border-slate-700"
                            >
                                <span className="font-semibold text-sm text-slate-700 dark:text-slate-200">
                                    {level.splitColumn || "Total"}
                                </span>
                                <div className="flex items-center gap-1">
                                    {/* Add Split Button (Only on last level) */}
                                    {index === levels.length - 1 && (
                                        <button 
                                            onClick={(e) => handleHeaderSplitClick(index, e)}
                                            className={`
                                                p-1 rounded hover:bg-slate-100 dark:hover:bg-slate-700 transition-colors
                                                ${level.selectedItemName ? 'text-blue-500' : 'text-slate-300 cursor-not-allowed'}
                                            `}
                                            title={level.selectedItemName ? "Split further" : "Select an item to split"}
                                            disabled={!level.selectedItemName}
                                        >
                                            <Plus className="w-4 h-4" />
                                        </button>
                                    )}
                                    
                                    {index > 0 && (
                                        <button onClick={() => closeSplit(index)} className="text-slate-400 hover:text-red-500">
                                            <X className="w-4 h-4" />
                                        </button>
                                    )}
                                </div>
                            </div>

                            {/* List */}
                            <div 
                                id={`list-${index}`}
                                className="flex-1 overflow-y-auto pr-2 space-y-2 scrollbar-thin scrollbar-thumb-slate-300 dark:scrollbar-thumb-slate-600"
                                onScroll={updatePaths}
                            >
                                {level.items.map((item) => {
                                    const isSelected = level.selectedItemName === item.name;
                                    const isMax = Math.max(...level.items.map(i => i.value));
                                    const barWidth = (item.value / isMax) * 100;

                                    return (
                                        <div 
                                            key={item.name}
                                            id={`node-${index}-${item.name}`}
                                            onClick={() => handleItemClick(index, item)}
                                            className={`
                                                relative p-3 rounded-md border cursor-pointer transition-all group
                                                ${isSelected 
                                                    ? 'bg-blue-50 border-blue-500 dark:bg-blue-900/20 dark:border-blue-500 shadow-md' 
                                                    : 'bg-white border-slate-200 dark:bg-slate-800 dark:border-slate-700 hover:border-blue-300 dark:hover:border-blue-700'
                                                }
                                            `}
                                        >
                                            <div className="flex justify-between items-center mb-1 relative z-10 gap-2">
                                                <span className="font-medium text-sm truncate flex-1 min-w-0" title={item.name}>
                                                    {item.name}
                                                </span>
                                                <span className="text-xs font-mono text-slate-500 dark:text-slate-400 whitespace-nowrap">
                                                    {item.value.toLocaleString()} ({Math.round(item.ratio * 100)}%)
                                                </span>
                                            </div>
                                            
                                            {/* Bar Background */}
                                            <div className="absolute bottom-0 left-0 h-1 bg-blue-500/20 transition-all duration-500" style={{ width: `${barWidth}%` }} />
                                        </div>
                                    );
                                })}
                            </div>
                        </div>
                    ))}
                
                {/* SVG Connections Layer */}
                <svg className="absolute inset-0 w-full h-full pointer-events-none z-0">
                    {paths.map((path, i) => (
                        <path
                            key={i}
                            d={path.d}
                            fill="none"
                            stroke="#3b82f6" // blue-500
                            strokeWidth="2"
                            strokeOpacity="0.5"
                        />
                    ))}
                </svg>
                </div>
            </div>

            {/* Split Menu */}
            {splitMenuOpen && (
                <div 
                    className="absolute z-50 bg-white dark:bg-slate-800 rounded-lg shadow-xl border border-slate-200 dark:border-slate-700 w-64 max-h-80 overflow-y-auto flex flex-col"
                    style={{ left: splitMenuOpen.x, top: splitMenuOpen.y }}
                >
                    <div className="p-3 border-b border-slate-100 dark:border-slate-700 bg-slate-50 dark:bg-slate-900 sticky top-0">
                        <span className="text-xs font-semibold text-slate-500 uppercase tracking-wider">Split by</span>
                    </div>
                    <div className="p-1">
                        {columns.map(col => (
                            <button
                                key={col}
                                onClick={() => handleSplit(col)}
                                className="w-full text-left px-3 py-2 text-sm text-slate-700 dark:text-slate-200 hover:bg-blue-50 dark:hover:bg-blue-900/30 rounded-md transition-colors"
                            >
                                {col}
                            </button>
                        ))}
                    </div>
                </div>
            )}
            
            {/* Backdrop for menu */}
            {splitMenuOpen && (
                <div className="fixed inset-0 z-40" onClick={() => setSplitMenuOpen(null)} />
            )}
        </div>
    );
};

import React, { useState } from 'react';
import { Clock, CheckCircle, AlertCircle, Loader2, ArrowLeft, Database, Columns, FileText, EyeOff, Play, Hash, AlignLeft, Calendar, Ban } from 'lucide-react';
import { EDAService } from '../../core/api/eda';
import { ModalShell } from '../shared';

interface JobsHistoryModalProps {
  isOpen: boolean;
  onClose: () => void;
  history: any[];
  onSelect: (report: any) => void;
  onFetchReport: (id: number) => Promise<any>;
  onRefresh?: () => void;
}

export const JobsHistoryModal: React.FC<JobsHistoryModalProps> = ({ isOpen, onClose, history, onSelect, onFetchReport, onRefresh }) => {
  const [selectedJob, setSelectedJob] = useState<any>(null);
  const [loading, setLoading] = useState(false);
  const [cancelling, setCancelling] = useState<number | null>(null);

  const handleClose = () => {
    setSelectedJob(null);
    onClose();
  };

  const handleCancel = async (e: React.MouseEvent, jobId: number) => {
    e.stopPropagation();
    if (confirm("Are you sure you want to cancel this analysis?")) {
        setCancelling(jobId);
        try {
            await EDAService.cancelJob(jobId);
            if (onRefresh) onRefresh();
        } catch (err) {
            console.error("Failed to cancel job", err);
            alert("Failed to cancel job");
        } finally {
            setCancelling(null);
        }
    }
  };

  const handleJobClick = async (job: any) => {
    setLoading(true);
    try {
        const fullReport = await onFetchReport(job.id);
        setSelectedJob(fullReport);
    } catch (err) {
        console.error("Failed to load report details", err);
    } finally {
        setLoading(false);
    }
  };

  const getIconForType = (dtype: string) => {
    switch (dtype) {
      case 'Numeric': return <Hash className="w-4 h-4 text-blue-500" />;
      case 'Categorical': return <AlignLeft className="w-4 h-4 text-purple-500" />;
      case 'DateTime': return <Calendar className="w-4 h-4 text-green-500" />;
      default: return <FileText className="w-4 h-4 text-gray-500" />;
    }
  };

  return (
    <ModalShell
      isOpen={isOpen}
      onClose={handleClose}
      size={selectedJob ? '5xl' : '2xl'}
      title={
        <div className="flex items-center gap-3">
          {selectedJob ? (
            <button
              onClick={() => setSelectedJob(null)}
              className="p-1 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-full transition-colors"
              aria-label="Back to history"
            >
              <ArrowLeft className="w-5 h-5 text-gray-500 dark:text-gray-400" />
            </button>
          ) : (
            <Clock className="w-5 h-5 text-blue-500" />
          )}
          <span className="text-xl font-semibold text-gray-900 dark:text-white">
            {selectedJob ? `Analysis #${selectedJob.id} Details` : 'Analysis History'}
          </span>
        </div>
      }
      footer={
        selectedJob ? (
          <div className="flex justify-end">
            <button
              onClick={() => {
                onSelect(selectedJob);
                handleClose();
              }}
              className="flex items-center px-4 py-2 bg-blue-600 text-white rounded-md hover:bg-blue-700 transition-colors shadow-sm"
            >
              <Play className="w-4 h-4 mr-2" />
              Load this Report
            </button>
          </div>
        ) : (
          <p className="text-sm text-gray-500 dark:text-gray-400 text-center w-full">
            Select a previous analysis to view details.
          </p>
        )
      }
    >
      <div className="p-6">
          {!selectedJob ? (
            history.length === 0 ? (
              <div className="text-center py-12 text-gray-500 dark:text-gray-400">
                <Clock className="w-12 h-12 mx-auto mb-3 opacity-20" />
                <p>No history available for this dataset.</p>
              </div>
            ) : (
              <div className="space-y-3">
                {history.map((job) => (
                  <div 
                    key={job.id}
                    onClick={() => handleJobClick(job)}
                    className="flex items-center justify-between p-4 rounded-lg border border-gray-200 dark:border-gray-700 hover:border-blue-500 dark:hover:border-blue-500 hover:bg-blue-50 dark:hover:bg-blue-900/20 cursor-pointer transition-all group"
                  >
                    <div className="flex items-center gap-4">
                      <div className={`p-2 rounded-full ${
                        job.status === 'COMPLETED' ? 'bg-green-100 text-green-600 dark:bg-green-900/30 dark:text-green-400' :
                        job.status === 'FAILED' ? 'bg-red-100 text-red-600 dark:bg-red-900/30 dark:text-red-400' :
                        job.status === 'CANCELLED' ? 'bg-gray-100 text-gray-600 dark:bg-gray-800 dark:text-gray-400' :
                        'bg-yellow-100 text-yellow-600 dark:bg-yellow-900/30 dark:text-yellow-400'
                      }`}>
                        {job.status === 'COMPLETED' ? <CheckCircle className="w-5 h-5" /> :
                         job.status === 'FAILED' ? <AlertCircle className="w-5 h-5" /> :
                         job.status === 'CANCELLED' ? <Ban className="w-5 h-5" /> :
                         <Loader2 className="w-5 h-5 animate-spin" />}
                      </div>
                      <div>
                        <div className="font-medium text-gray-900 dark:text-white group-hover:text-blue-600 dark:group-hover:text-blue-400 flex items-center gap-2">
                          Analysis #{job.id}
                          <span className={`text-xs px-2 py-0.5 rounded-full border ${
                            job.status === 'COMPLETED' ? 'bg-green-50 text-green-700 border-green-200 dark:bg-green-900/20 dark:text-green-300 dark:border-green-800' :
                            job.status === 'FAILED' ? 'bg-red-50 text-red-700 border-red-200 dark:bg-red-900/20 dark:text-red-300 dark:border-red-800' :
                            job.status === 'CANCELLED' ? 'bg-gray-50 text-gray-700 border-gray-200 dark:bg-gray-800 dark:text-gray-300 dark:border-gray-700' :
                            'bg-yellow-50 text-yellow-700 border-yellow-200 dark:bg-yellow-900/20 dark:text-yellow-300 dark:border-yellow-800'
                          }`}>
                            {job.status}
                          </span>
                        </div>
                        <div className="text-sm text-gray-500 dark:text-gray-400">
                          {new Date(job.created_at).toLocaleString()}
                        </div>
                        {job.target_col && (
                            <div className="text-xs text-gray-400 mt-1 flex items-center gap-1">
                                <Play className="w-3 h-3" /> Target: {job.target_col}
                                {job.task_type && (
                                    <span className="ml-1 px-1.5 py-0.5 bg-gray-100 dark:bg-gray-700 rounded text-[10px]">
                                        {job.task_type}
                                    </span>
                                )}
                            </div>
                        )}
                      </div>
                    </div>
                    
                    <div className="text-right flex items-center gap-4">
                      {/* Cancel Button for Pending/Running Jobs */}
                      {(job.status === 'PENDING' || job.status === 'STARTED' || job.status === 'RUNNING') && (
                        <button
                            onClick={(e) => handleCancel(e, job.id)}
                            disabled={cancelling === job.id}
                            className="p-2 text-gray-400 hover:text-red-500 hover:bg-red-50 dark:hover:bg-red-900/20 rounded-full transition-colors"
                            title="Cancel Analysis"
                        >
                            {cancelling === job.id ? (
                                <Loader2 className="w-4 h-4 animate-spin" />
                            ) : (
                                <Ban className="w-4 h-4" />
                            )}
                        </button>
                      )}
                      
                      {/* Note: excluded_columns is not available in history list summary */}
                    </div>
                  </div>
                ))}
              </div>
            )
          ) : loading ? (
            <div className="flex flex-col items-center justify-center h-64 text-gray-500">
                <Loader2 className="w-12 h-12 mb-4 animate-spin text-blue-500" />
                <p>Loading analysis details...</p>
            </div>
          ) : (
            <div className="space-y-8">
                {/* Overview Stats */}
                <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
                    <div className="bg-gray-50 dark:bg-gray-900/50 p-4 rounded-lg border border-gray-200 dark:border-gray-700">
                        <div className="flex items-center gap-2 text-gray-500 dark:text-gray-400 mb-1">
                            <Database className="w-4 h-4" />
                            <span className="text-xs uppercase font-medium">Rows</span>
                        </div>
                        <div className="text-2xl font-bold text-gray-900 dark:text-white">
                            {selectedJob.profile_data?.row_count?.toLocaleString() || '-'}
                        </div>
                    </div>
                    <div className="bg-gray-50 dark:bg-gray-900/50 p-4 rounded-lg border border-gray-200 dark:border-gray-700">
                        <div className="flex items-center gap-2 text-gray-500 dark:text-gray-400 mb-1">
                            <Columns className="w-4 h-4" />
                            <span className="text-xs uppercase font-medium">Columns</span>
                        </div>
                        <div className="text-2xl font-bold text-gray-900 dark:text-white">
                            {selectedJob.profile_data?.column_count?.toLocaleString() || '-'}
                        </div>
                    </div>
                    <div className="bg-gray-50 dark:bg-gray-900/50 p-4 rounded-lg border border-gray-200 dark:border-gray-700">
                        <div className="flex items-center gap-2 text-gray-500 dark:text-gray-400 mb-1">
                            <FileText className="w-4 h-4" />
                            <span className="text-xs uppercase font-medium">Missing Cells</span>
                        </div>
                        <div className="text-2xl font-bold text-gray-900 dark:text-white">
                            {selectedJob.profile_data?.missing_cells_percentage?.toFixed(1)}%
                        </div>
                    </div>
                </div>

                {/* Excluded Columns */}
                {selectedJob.profile_data?.excluded_columns && selectedJob.profile_data.excluded_columns.length > 0 && (
                    <div>
                        <h3 className="text-sm font-medium text-gray-900 dark:text-white mb-3 flex items-center gap-2">
                            <EyeOff className="w-4 h-4 text-gray-500" />
                            Excluded Columns ({selectedJob.profile_data.excluded_columns.length})
                        </h3>
                        <div className="flex flex-wrap gap-2">
                            {selectedJob.profile_data.excluded_columns.map((col: string) => (
                                <span key={col} className="px-2 py-1 bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 rounded text-sm line-through">
                                    {col}
                                </span>
                            ))}
                        </div>
                    </div>
                )}

                {/* Variables List */}
                <div>
                    <h3 className="text-sm font-medium text-gray-900 dark:text-white mb-3">Variables Overview</h3>
                    <div className="border border-gray-200 dark:border-gray-700 rounded-lg overflow-hidden">
                        <table className="w-full text-sm text-left">
                            <thead className="bg-gray-50 dark:bg-gray-900/50 text-gray-500 dark:text-gray-400">
                                <tr>
                                    <th className="px-4 py-3 font-medium">Name</th>
                                    <th className="px-4 py-3 font-medium">Type</th>
                                    <th className="px-4 py-3 font-medium">Missing</th>
                                    <th className="px-4 py-3 font-medium">Distinct</th>
                                </tr>
                            </thead>
                            <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                                {selectedJob.profile_data?.columns && Object.values(selectedJob.profile_data.columns).map((v: any) => (
                                    <tr key={v.name} className="hover:bg-gray-50 dark:hover:bg-gray-800/50">
                                        <td className="px-4 py-3 font-medium text-gray-900 dark:text-white">{v.name}</td>
                                        <td className="px-4 py-3">
                                            <div className="flex items-center gap-2">
                                                {getIconForType(v.dtype)}
                                                <span>{v.dtype}</span>
                                            </div>
                                        </td>
                                        <td className="px-4 py-3">
                                            {v.missing_percentage > 0 ? (
                                                <span className="text-amber-600">{v.missing_percentage.toFixed(1)}%</span>
                                            ) : (
                                                <span className="text-green-600">0%</span>
                                            )}
                                        </td>
                                        <td className="px-4 py-3 text-gray-500 dark:text-gray-400">
                                            {v.categorical_stats?.unique_count || '-'}
                                        </td>
                                    </tr>
                                ))}
                            </tbody>
                        </table>
                    </div>
                </div>
            </div>
          )}
      </div>
    </ModalShell>
  );
};

import React from 'react';
import { BarChart, Bar, ResponsiveContainer } from 'recharts';
import { AlertTriangle, Hash, Type, Calendar, AlignLeft, EyeOff, Eye } from 'lucide-react';

interface VariableCardProps {
  profile: any;
  onClick: () => void;
  onToggleExclude?: (colName: string, exclude: boolean) => void;
  isExcluded?: boolean;
}

export const VariableCard: React.FC<VariableCardProps> = ({ profile, onClick, onToggleExclude, isExcluded = false }) => {
  const getIcon = () => {
    if (isExcluded) return <Type className="w-4 h-4 text-gray-400" />;
    switch (profile.dtype) {
      case 'Numeric': return <Hash className="w-4 h-4 text-blue-500" />;
      case 'Categorical': return <AlignLeft className="w-4 h-4 text-purple-500" />;
      case 'DateTime': return <Calendar className="w-4 h-4 text-green-500" />;
      default: return <Type className="w-4 h-4 text-gray-500" />;
    }
  };

  // Prepare mini histogram data if available
  let miniChartData: any[] = [];
  
  if (profile.dtype === 'Numeric' && profile.histogram) {
      miniChartData = profile.histogram.map((b: any) => ({ name: b.start.toFixed(1), count: b.count }));
  } else if (profile.dtype === 'Text' && profile.histogram) {
      miniChartData = profile.histogram.map((b: any) => ({ name: b.start.toFixed(0), count: b.count }));
  } else if (profile.dtype === 'DateTime' && profile.histogram) {
      miniChartData = profile.histogram.map((b: any) => ({ name: new Date(b.start).toLocaleDateString(), count: b.count }));
  } else if (profile.dtype === 'Categorical' && profile.categorical_stats?.top_k) {
      miniChartData = profile.categorical_stats.top_k.slice(0, 5).map((k: any) => ({ name: k.value, count: k.count }));
  }

  return (
    <div 
      className={`rounded-lg border p-4 transition-all cursor-pointer flex flex-col h-full ${
        isExcluded 
          ? 'bg-gray-50 border-gray-200 dark:bg-gray-900 dark:border-gray-800 opacity-75' 
          : 'bg-white dark:bg-gray-800 border-gray-200 dark:border-gray-700 hover:shadow-md'
      }`}
      onClick={onClick}
    >
      <div className="flex justify-between items-start mb-2">
        <div className="flex items-center gap-2 w-full">
          {getIcon()}
          <h3 className={`font-medium text-sm truncate flex-1 ${isExcluded ? 'text-gray-500 line-through' : ''}`} title={profile.name}>
            {profile.name}
          </h3>
        </div>
      </div>

      <div className="flex items-center gap-2 mb-3">
            {!isExcluded && (
                <span className="px-2 py-0.5 text-xs font-medium bg-gray-100 dark:bg-gray-700 text-gray-600 dark:text-gray-300 rounded-full">
                {profile.dtype}
                </span>
            )}
            {onToggleExclude && (
                <button 
                    onClick={(e) => {
                        e.stopPropagation();
                        onToggleExclude(profile.name, !isExcluded);
                    }}
                    className={`p-1 rounded transition-colors ml-auto ${
                        isExcluded 
                            ? 'hover:bg-green-100 text-gray-400 hover:text-green-600 dark:hover:bg-green-900/30' 
                            : 'hover:bg-red-100 text-gray-400 hover:text-red-500 dark:hover:bg-red-900/30'
                    }`}
                    title={isExcluded ? "Include in analysis" : "Exclude from analysis"}
                >
                    {isExcluded ? <Eye className="w-3 h-3" /> : <EyeOff className="w-3 h-3" />}
                </button>
            )}
      </div>

      {!isExcluded && (
      <div className="flex justify-between items-end mt-auto">
        <div className="text-xs text-gray-500 space-y-1">
          {profile.missing_percentage > 0 && (
            <div className="flex items-center text-amber-600">
              <AlertTriangle className="w-3 h-3 mr-1" />
              {profile.missing_percentage.toFixed(1)}% null
            </div>
          )}
          {profile.is_unique && <div className="text-blue-500">Unique ID</div>}
          {profile.is_constant && <div className="text-red-500">Constant</div>}
          {profile.normality_test && profile.normality_test.is_normal && (
             <div className="text-purple-600" title={`Normal Distribution (p=${profile.normality_test.p_value.toFixed(3)})`}>Normal Dist.</div>
          )}
          {profile.normality_test && !profile.normality_test.is_normal && (
             <div className="text-amber-600" title={`Not Normal Distribution (p=${profile.normality_test.p_value.toFixed(3)})`}>Not Normal Dist.</div>
          )}
          {!profile.is_unique && !profile.is_constant && profile.missing_percentage === 0 && !profile.normality_test && (
             <div className="text-green-600">Healthy</div>
          )}
        </div>

        {/* Mini Chart */}
        {miniChartData.length > 0 && (
          <div className="h-12 w-24">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={miniChartData}>
                <Bar 
                    dataKey="count" 
                    fill={profile.dtype === 'Numeric' ? '#3b82f6' : profile.dtype === 'Categorical' ? '#8b5cf6' : '#10b981'} 
                    radius={[2, 2, 0, 0]} 
                />
              </BarChart>
            </ResponsiveContainer>
          </div>
        )}
      </div>
      )}
      {isExcluded && (
          <div className="mt-4 text-xs text-center text-gray-400 italic">
              Excluded from analysis
          </div>
      )}
    </div>
  );
};

import React, { useRef, useState } from 'react';
import { toPng } from 'html-to-image';
import { 
    ChevronDown, 
    ChevronRight, 
    Download,
    Eye,
    EyeOff,
    Loader2,
    Check
} from 'lucide-react';
import { BarChart, Bar, ResponsiveContainer } from 'recharts';
import { DistributionChart } from './DistributionChart';
import { Button } from '../ui/button';
import { Badge } from '../ui/badge';
import { InfoTooltip } from '../ui/InfoTooltip';

interface VariableRowProps {
    profile: any;
    isExpanded: boolean;
    onToggleExpand: () => void;
    onToggleExclude: (colName: string, exclude: boolean) => void;
    isExcluded: boolean;
    handleAddFilter: (column: string, value: any, operator: string) => void;
}

export const VariableRow: React.FC<VariableRowProps> = ({ 
    profile, 
    isExpanded, 
    onToggleExpand, 
    onToggleExclude,
    isExcluded,
    handleAddFilter
}) => {
    const chartRef = useRef<HTMLDivElement>(null);
    const [dlState, setDlState] = useState<'idle' | 'downloading' | 'done'>('idle');

    // Prepare mini histogram data
    let miniChartData: any[] = [];
    if (profile.histogram) {
        miniChartData = profile.histogram.map((b: any) => ({ name: String(b.start), count: b.count }));
    } else if (profile.categorical_stats?.top_k) {
        miniChartData = profile.categorical_stats.top_k.slice(0, 10).map((k: any) => ({ name: k.value, count: k.count }));
    }
    
    // Fallback for mini chart data if not directly available in standard path
    if (miniChartData.length === 0 && profile.dtype === 'Numeric' && profile.numeric_stats) {
        // Can't really plot without histogram data
    }

    const downloadChart = async () => {
        if (!chartRef.current) return;
        setDlState('downloading');

        try {
            const isDark = document.documentElement.classList.contains('dark');
            const dataUrl = await toPng(chartRef.current, {
                backgroundColor: isDark ? '#1f2937' : '#ffffff',
                pixelRatio: 2,
            });
            const link = document.createElement('a');
            link.href = dataUrl;
            link.download = `${profile.name}_distribution.png`;
            link.click();
        } catch (error) {
            console.error('Failed to download chart', error);
        } finally {
            setDlState('done');
            setTimeout(() => setDlState('idle'), 1200);
        }
    };

    const onBarClick = (data: any) => {
        if (profile.dtype === 'Categorical' || profile.dtype === 'Boolean') {
             const val = data.value !== undefined ? data.value : data.name; // Fallback to name if value missing
             handleAddFilter(profile.name, val, '==');
        } else if (profile.dtype === 'Numeric') {
             if (data.rawBin) {
                 // Try to add >= start
                 handleAddFilter(profile.name, data.rawBin.start, '>=');
             }
        }
    };

    const getTypeColor = (type: string) => {
        switch (type) {
            case 'Numeric': return 'bg-blue-100 text-blue-800 dark:bg-blue-900/30 dark:text-blue-300';
            case 'Categorical': return 'bg-orange-100 text-orange-800 dark:bg-orange-900/30 dark:text-orange-300';
            case 'Boolean': return 'bg-purple-100 text-purple-800 dark:bg-purple-900/30 dark:text-purple-300';
            case 'DateTime': return 'bg-cyan-100 text-cyan-800 dark:bg-cyan-900/30 dark:text-cyan-300';
            case 'Text': return 'bg-slate-100 text-slate-800 dark:bg-slate-800 dark:text-slate-300';
            default: return 'bg-gray-100 text-gray-800 dark:bg-gray-800 dark:text-gray-300';
        }
    };

    // Summary stats for the closed state row
    const renderSummary = () => {
        return (
            <div className="flex items-center justify-between w-full pr-4">
                <div className="flex gap-4 text-xs text-muted-foreground mr-auto">
                    {profile.numeric_stats ? (
                        <>
                            <span>Mean: <span className="font-mono text-foreground">{profile.numeric_stats.mean?.toFixed(2)}</span></span>
                            <span>Std: <span className="font-mono text-foreground">{profile.numeric_stats.std?.toFixed(2)}</span></span>
                            <span>Min: <span className="font-mono text-foreground">{profile.numeric_stats.min?.toFixed(2)}</span></span>
                            <span>Max: <span className="font-mono text-foreground">{profile.numeric_stats.max?.toFixed(2)}</span></span>
                        </>
                    ) : profile.categorical_stats ? (
                        <>
                            <span>Unique: <span className="font-mono text-foreground">{profile.categorical_stats.unique_count}</span></span>
                            {profile.categorical_stats.top_k?.[0] && (
                                <span>Top: <span className="font-mono text-foreground">{String(profile.categorical_stats.top_k[0].value).slice(0, 20)}</span></span>
                            )}
                        </>
                    ) : null}

                    {/* Normality / Status Indicators */}
                    {profile.normality_test && profile.normality_test.is_normal && (
                        <Badge variant="outline" className="text-[10px] h-4 text-purple-600 border-purple-200 bg-purple-50">
                            Normal Dist
                        </Badge>
                    )}
                    {profile.normality_test && !profile.normality_test.is_normal && (
                        <Badge variant="outline" className="text-[10px] h-4 text-amber-600 border-amber-200 bg-amber-50">
                            Not Normal
                        </Badge>
                    )}
                </div>

                {/* Mini Histogram */}
                {miniChartData.length > 0 && (
                    <div className="h-8 w-24 hidden sm:block opacity-70">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart data={miniChartData}>
                                <Bar 
                                    dataKey="count" 
                                    fill={profile.dtype === 'Numeric' ? '#3b82f6' : profile.dtype === 'Categorical' ? '#8b5cf6' : '#10b981'} 
                                    radius={[1, 1, 0, 0]} 
                                />
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                )}
            </div>
        );
    };

    return (
        <div className={`border rounded-lg mb-2 transition-all ${isExpanded ? 'border-primary/50 shadow-md bg-card/50' : 'border-border bg-card'}`}>
            <div 
                className="flex items-center p-3 hover:bg-accent/50 cursor-pointer rounded-t-lg"
                onClick={onToggleExpand}
            >
                <div className="mr-2 text-muted-foreground">
                    {isExpanded ? <ChevronDown size={18} /> : <ChevronRight size={18} />}
                </div>
                
                <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 mb-1">
                        <span className="font-medium text-sm truncate">{profile.name}</span>
                        <Badge variant="outline" className={`text-[10px] h-5 px-1 ${getTypeColor(profile.dtype)}`}>
                            {profile.dtype}
                        </Badge>
                        {profile.is_unique && <Badge variant="secondary" className="text-[10px] h-5">ID</Badge>}
                        {profile.is_constant && <Badge variant="destructive" className="text-[10px] h-5">Constant</Badge>}
                    </div>
                    
                    {!isExpanded && renderSummary()}
                </div>

                <div className="flex items-center gap-4 px-2">
                    {/* Missing Bar */}
                    <div className="flex flex-col items-end w-24">
                        <div className="flex items-center gap-1 mb-1">
                            <span className="text-[10px] text-muted-foreground">
                                {profile.missing_percentage > 0 ? `${profile.missing_percentage.toFixed(1)}% Missing` : '100% Present'}
                            </span>
                             <InfoTooltip text="Green bar indicates the percentage of valid (non-null) data. Full green means no missing values." align="end" size="sm" />
                        </div>
                        <div className="w-full h-1.5 bg-gray-100 dark:bg-gray-800 rounded-full overflow-hidden">
                            <div 
                                className={`h-full ${profile.missing_percentage > 0 ? 'bg-amber-400' : 'bg-green-500'}`} 
                                style={{ width: `${Math.max(100 - profile.missing_percentage, 0)}%` }}
                            />
                        </div>
                    </div>

                    <div className="h-8 w-[1px] bg-border mx-2" />

                    <Button
                        variant="ghost"
                        size="icon"
                        className="h-8 w-8 text-muted-foreground"
                        onClick={(e) => {
                            e.stopPropagation();
                            onToggleExclude(profile.name, !isExcluded);
                        }}
                    >
                        {isExcluded ? <EyeOff size={16} /> : <Eye size={16} />}
                    </Button>
                </div>
            </div>

            {isExpanded && (
                <div className="p-4 border-t border-border bg-card/30 animate-in slide-in-from-top-2 duration-200">
                    <div className="grid grid-cols-1 md:grid-cols-3 gap-6 items-stretch">
                        
                        {/* Stats Column */}
                        <div className="space-y-4">
                            <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Statistics</h4>
                            <div className="bg-background rounded-md border p-3 text-sm space-y-2 font-mono">
                                <div className="flex justify-between">
                                    <span className="text-muted-foreground">Missing</span>
                                    <span>{profile.missing_count} ({profile.missing_percentage.toFixed(2)}%)</span>
                                </div>
                                {profile.numeric_stats && (
                                    <>
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">Mean</span>
                                            <span>{profile.numeric_stats.mean?.toFixed(4)}</span>
                                        </div>
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">Std Dev</span>
                                            <span>{profile.numeric_stats.std?.toFixed(4)}</span>
                                        </div>
                                        {/* Added Variance */}
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">Variance</span>
                                            <span>{profile.numeric_stats.variance?.toFixed(4) || (Math.pow(profile.numeric_stats.std || 0, 2)).toFixed(4)}</span>
                                        </div>
                                        <div className="my-2 border-t border-dashed" />
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">Min</span>
                                            <span>{profile.numeric_stats.min?.toFixed(4)}</span>
                                        </div>
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">25% (Q1)</span>
                                            <span>{profile.numeric_stats.q25?.toFixed(4)}</span>
                                        </div>
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">Median</span>
                                            <span>{profile.numeric_stats.median?.toFixed(4)}</span>
                                        </div>
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">75% (Q3)</span>
                                            <span>{profile.numeric_stats.q75?.toFixed(4)}</span>
                                        </div>
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">Max</span>
                                            <span>{profile.numeric_stats.max?.toFixed(4)}</span>
                                        </div>
                                        <div className="my-2 border-t border-dashed" />
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">Skewness</span>
                                            <span>{profile.numeric_stats.skewness?.toFixed(4)}</span>
                                        </div>
                                        {profile.numeric_stats.skewness != null && (
                                            <div className="text-[10px] text-muted-foreground pl-2">
                                                {Math.abs(profile.numeric_stats.skewness) < 0.5 ? '↳ Symmetric' : 
                                                 Math.abs(profile.numeric_stats.skewness) < 1 ? '↳ Moderately Skewed' : '↳ Highly Skewed'}
                                            </div>
                                        )}
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">Kurtosis</span>
                                            <span>{profile.numeric_stats.kurtosis?.toFixed(4)}</span>
                                        </div>
                                        {profile.numeric_stats.kurtosis != null && (
                                            <div className="text-[10px] text-muted-foreground pl-2">
                                                {Math.abs(profile.numeric_stats.kurtosis) < 0.5 ? '↳ Mesokurtic (Normal-like)' : 
                                                 profile.numeric_stats.kurtosis > 0 ? '↳ Leptokurtic (Heavy Tails)' : '↳ Platykurtic (Light Tails)'}
                                            </div>
                                        )}
                                        <div className="my-2 border-t border-dashed" />
                                        {profile.numeric_stats.zeros_count != null && (
                                            <div className="flex justify-between">
                                                <span className="text-muted-foreground">Zeros</span>
                                                <span>{profile.numeric_stats.zeros_count}</span>
                                            </div>
                                        )}
                                        {profile.numeric_stats.negatives_count != null && (
                                            <div className="flex justify-between">
                                                <span className="text-muted-foreground">Negatives</span>
                                                <span>{profile.numeric_stats.negatives_count}</span>
                                            </div>
                                        )}
                                        {profile.vif != null && (
                                            <div className="flex justify-between items-center">
                                                <span className="text-muted-foreground flex items-center gap-1">
                                                    VIF
                                                    <InfoTooltip text="Variance Inflation Factor. VIF > 5 = high multicollinearity, VIF > 10 = severe." size="sm" />
                                                </span>
                                                <span className={profile.vif > 5 ? 'text-red-500 font-semibold' : profile.vif > 2 ? 'text-amber-500' : 'text-green-500'}>
                                                    {profile.vif.toFixed(2)}
                                                </span>
                                            </div>
                                        )}
                                    </>
                                )}
                                {profile.text_stats && (
                                    <>
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">Avg Length</span>
                                            <span>{profile.text_stats.avg_length?.toFixed(1)} chars</span>
                                        </div>
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">Min Length</span>
                                            <span>{profile.text_stats.min_length}</span>
                                        </div>
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">Max Length</span>
                                            <span>{profile.text_stats.max_length}</span>
                                        </div>
                                        {profile.text_stats.sentiment_distribution && (
                                            <>
                                                <div className="my-2 border-t border-dashed" />
                                                <div className="text-xs font-semibold mb-1">Sentiment</div>
                                                <div className="flex h-3 rounded-full overflow-hidden w-full bg-secondary">
                                                    <div className="bg-green-500 h-full" style={{ width: `${(profile.text_stats.sentiment_distribution.positive || 0) * 100}%` }} title={`Positive: ${((profile.text_stats.sentiment_distribution.positive || 0) * 100).toFixed(1)}%`}></div>
                                                    <div className="bg-gray-400 h-full" style={{ width: `${(profile.text_stats.sentiment_distribution.neutral || 0) * 100}%` }} title={`Neutral: ${((profile.text_stats.sentiment_distribution.neutral || 0) * 100).toFixed(1)}%`}></div>
                                                    <div className="bg-red-500 h-full" style={{ width: `${(profile.text_stats.sentiment_distribution.negative || 0) * 100}%` }} title={`Negative: ${((profile.text_stats.sentiment_distribution.negative || 0) * 100).toFixed(1)}%`}></div>
                                                </div>
                                                <div className="flex justify-between text-[10px] text-muted-foreground mt-1 px-1">
                                                    <span>Pos: {((profile.text_stats.sentiment_distribution.positive || 0) * 100).toFixed(0)}%</span>
                                                    <span>Neu: {((profile.text_stats.sentiment_distribution.neutral || 0) * 100).toFixed(0)}%</span>
                                                    <span>Neg: {((profile.text_stats.sentiment_distribution.negative || 0) * 100).toFixed(0)}%</span>
                                                </div>
                                            </>
                                        )}
                                        {profile.text_stats.common_words && profile.text_stats.common_words.length > 0 && (
                                            <>
                                                 <div className="my-2 border-t border-dashed" />
                                                 <div className="text-xs font-semibold mb-1">Common Words</div>
                                                 <div className="flex flex-wrap gap-1">
                                                    {profile.text_stats.common_words.slice(0, 10).map((w: any, idx: number) => (
                                                        <Badge key={idx} variant="secondary" className="text-[10px] h-4">
                                                            {w.word || w.value} ({w.count})
                                                        </Badge>
                                                    ))}
                                                 </div>
                                            </>
                                        )}
                                    </>
                                )}
                                {profile.categorical_stats && (
                                    <>
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">Unique</span>
                                            <span>{profile.categorical_stats.unique_count}</span>
                                        </div>
                                        <div className="flex justify-between">
                                            <span className="text-muted-foreground">Mode</span>
                                            <span className="truncate max-w-[100px]" title={String(profile.categorical_stats.top_k?.[0]?.value)}>
                                                {String(profile.categorical_stats.top_k?.[0]?.value || '-')}
                                            </span>
                                        </div>
                                        {profile.categorical_stats.rare_labels_count != null && (
                                            <div className="flex justify-between">
                                                <span className="text-muted-foreground">Rare Labels</span>
                                                <span>{profile.categorical_stats.rare_labels_count}</span>
                                            </div>
                                        )}
                                        {profile.categorical_stats.top_k && profile.categorical_stats.top_k.length > 0 && (
                                            <>
                                                <div className="my-2 border-t border-dashed" />
                                                <div className="text-xs font-semibold mb-1">Top Categories</div>
                                                <div className="space-y-1">
                                                    {profile.categorical_stats.top_k.slice(0, 5).map((item: any, i: number) => (
                                                        <div key={i} className="flex justify-between text-xs">
                                                            <span className="truncate max-w-[120px]" title={String(item.value)}>{String(item.value)}</span>
                                                            <span className="text-muted-foreground">{item.count}</span>
                                                        </div>
                                                    ))}
                                                </div>
                                            </>
                                        )}
                                    </>
                                )}
                            </div>
                        </div>

                        {/* Distribution Chart Column */}
                        <div className="md:col-span-2 flex flex-col min-h-[300px]">
                            <div className="flex items-center justify-between mb-2">
                                <h4 className="text-xs font-semibold uppercase tracking-wider text-muted-foreground">Distribution</h4>
                                <Button size="icon" variant="outline" className="h-8 w-8" title="Download Chart" onClick={downloadChart} disabled={dlState !== 'idle'}>
                                    {dlState === 'downloading' ? <Loader2 size={16} className="animate-spin" /> : dlState === 'done' ? <Check size={16} className="text-green-500" /> : <Download size={16} />}
                                </Button>
                            </div>
                            <div className="flex-1 bg-background rounded-md border p-4 min-h-0" ref={chartRef}>
                                <DistributionChart profile={profile} onBarClick={onBarClick} />
                            </div>
                        </div>
                    </div>
                </div>
            )}
        </div>
    );
};

import React, { useState, useMemo } from 'react';
import { useGraphStore } from '../../core/store/useGraphStore';
import { useViewStore } from '../../core/store/useViewStore';
import { ChevronUp, ChevronDown, ChevronRight, Table, Layers, GitBranch, AlertTriangle, Wand2 } from 'lucide-react';
import type { NodeExecutionResult, PreviewDataRows, PreviewData } from '../../core/api/client';
import { generateBranchColors } from '../../core/hooks/useBranchColors';

/** Convert a PreviewData payload into a {tabName -> rows} map. */
function toDatasetMap(previewData: PreviewData | null | undefined): Record<string, PreviewDataRows> {
  if (!previewData) return {};
  if (Array.isArray(previewData)) return { Result: previewData as PreviewDataRows };
  if (typeof previewData === 'object') return previewData as Record<string, PreviewDataRows>;
  return {};
}

export const ResultsPanel: React.FC = () => {
  const executionResult = useGraphStore((state) => state.executionResult);
  const canvasNodes = useGraphStore((state) => state.nodes);
  const chainSiblings = useGraphStore((state) => state.chainSiblings);
  const { isResultsPanelExpanded, setResultsPanelExpanded } = useViewStore();
  const [activeBranch, setActiveBranch] = useState<string | null>(null);
  const [activeTab, setActiveTab] = useState<string | null>(null);
  const [mergeWarningsOpen, setMergeWarningsOpen] = useState<boolean>(false);

  // Map node id → readable label (falls back to a prettified definitionType
  // so users see "Drop Rows" instead of "drop_rows-04475cca-eef7-4fdb-...").
  const nodeLabelMap = useMemo(() => {
    const map: Record<string, string> = {};
    for (const n of canvasNodes) {
      const data = (n.data ?? {}) as Record<string, unknown>;
      const label =
        (data.label as string) ||
        (data.title as string) ||
        (typeof data.definitionType === 'string'
          ? (data.definitionType as string)
              .replace(/_/g, ' ')
              .replace(/\b\w/g, (c) => c.toUpperCase())
          : n.id);
      map[n.id] = label;
    }
    return map;
  }, [canvasNodes]);

  // Branch labels (only when backend returned multiple branches)
  const branchLabels = useMemo(() => {
    const bp = executionResult?.branch_previews;
    if (!bp) return [];
    const keys = Object.keys(bp);
    return keys.length > 1 ? keys : [];
  }, [executionResult]);

  const branchColors = useMemo(
    () => generateBranchColors(branchLabels.length),
    [branchLabels.length],
  );

  // Pick default branch when branches change
  React.useEffect(() => {
    if (branchLabels.length > 0 && (!activeBranch || !branchLabels.includes(activeBranch))) {
      setActiveBranch(branchLabels[0]);
    } else if (branchLabels.length === 0 && activeBranch !== null) {
      setActiveBranch(null);
    }
  }, [branchLabels, activeBranch]);

  // Dataset tabs for the active branch (or top-level preview when single-branch)
  const datasets = useMemo(() => {
    if (branchLabels.length > 0 && activeBranch && executionResult?.branch_previews) {
      return toDatasetMap(executionResult.branch_previews[activeBranch]);
    }
    return toDatasetMap(executionResult?.preview_data);
  }, [executionResult, branchLabels, activeBranch]);

  const tabNames = Object.keys(datasets);

  // Set default split tab when datasets change
  React.useEffect(() => {
    if (tabNames.length > 0 && (!activeTab || !tabNames.includes(activeTab))) {
      if (tabNames.includes('train')) setActiveTab('train');
      else if (tabNames.includes('X')) setActiveTab('X');
      else setActiveTab(tabNames[0]);
    }
  }, [tabNames, activeTab]);

  // Engine-emitted merge advisories (sibling fan-in etc.) - surfaced so users
  // immediately see when a downstream node is silently merging parallel
  // branches that share an ancestor. When a branch tab is active we only
  // show advisories for nodes that actually ran in that branch, otherwise
  // the banner would flag warnings for nodes the user can't even see on
  // the current tab.
  // NOTE: this useMemo must run on every render (i.e. before any early
  // return below) to preserve React's hook call order.
  const rawMergeWarnings = executionResult?.merge_warnings;
  const branchNodeIdsMemo = executionResult?.branch_node_ids;
  const mergeWarnings = useMemo(() => {
    const all = rawMergeWarnings ?? [];
    if (!activeBranch || !branchNodeIdsMemo || !branchNodeIdsMemo[activeBranch]) {
      return all;
    }
    const branchNodes = new Set(branchNodeIdsMemo[activeBranch]);
    return all.filter((w) => branchNodes.has(w.node_id));
  }, [rawMergeWarnings, activeBranch, branchNodeIdsMemo]);

  if (!executionResult) return null;

  const currentRows = (activeTab && datasets[activeTab]) ? datasets[activeTab] : [];
  const columns = currentRows.length > 0 ? Object.keys(currentRows[0] ?? {}) : [];
  // When viewing a specific branch, restrict the applied-steps pills to nodes
  // that actually ran in that branch (otherwise every tab shows every node).
  const allNodeIds = executionResult.node_results ? Object.keys(executionResult.node_results) : [];
  const branchNodeIds = executionResult.branch_node_ids;
  const applied_steps = (branchNodeIds && activeBranch && branchNodeIds[activeBranch])
    ? branchNodeIds[activeBranch]
    : allNodeIds;

  // Check for errors
  const nodeResults = executionResult.node_results || {};
  const errorNodeId = Object.keys(nodeResults).find((nodeId) => {
    const result: NodeExecutionResult | undefined = nodeResults[nodeId];
    return result?.status === 'failed';
  });
  const error = errorNodeId ? nodeResults[errorNodeId]?.error : null;

  return (
    <div 
      className={`absolute bottom-0 left-0 right-0 bg-background border-t shadow-[0_-4px_6px_-1px_rgba(0,0,0,0.1)] transition-all duration-300 z-20 flex flex-col ${
        isResultsPanelExpanded ? 'h-96' : 'h-10'
      }`}
    >
      {/* Header */}
      <div 
        className="flex items-center justify-between px-4 py-2 bg-muted/10 cursor-pointer hover:bg-muted/20 border-b select-none"
        onClick={() => setResultsPanelExpanded(!isResultsPanelExpanded)}
      >
        <div className="flex items-center gap-2">
          <Table className="w-4 h-4 text-primary" />
          <span className="font-semibold text-sm">Preview Results</span>
          <span className="text-xs text-muted-foreground ml-2">
            {currentRows.length} rows shown
          </span>
          {branchLabels.length > 0 && (
            <span className="text-xs text-muted-foreground ml-2">
              · {branchLabels.length} branches
            </span>
          )}
          {executionResult.status === 'failed' && (
            <span className="text-xs text-red-600 font-bold ml-2">
              (Failed)
            </span>
          )}
        </div>
        <button className="p-1 hover:bg-muted rounded">
          {isResultsPanelExpanded ? <ChevronDown className="w-4 h-4" /> : <ChevronUp className="w-4 h-4" />}
        </button>
      </div>

      {/* Content */}
      {isResultsPanelExpanded && (
        <div className="flex-1 overflow-hidden flex flex-col">
          {/* Error Message */}
          {executionResult.status === 'failed' && (
             <div className="p-4 bg-red-50 border-b text-red-800 text-sm overflow-auto max-h-32">
                <div className="font-bold mb-1">Pipeline Execution Failed</div>
                <div className="font-mono text-xs whitespace-pre-wrap">{error || 'Unknown error occurred during execution.'}</div>
             </div>
          )}

          {/* Branch Tabs (multi-branch parallel runs only) */}
          {branchLabels.length > 0 && (
            <div className="flex items-center gap-1 px-2 pt-2 border-b bg-muted/10">
              <GitBranch className="w-3 h-3 text-muted-foreground mr-1" />
              {branchLabels.map((label, idx) => {
                const isActive = activeBranch === label;
                return (
                  <button
                    key={label}
                    onClick={() => { setActiveBranch(label); setActiveTab(null); }}
                    className={`flex items-center gap-1.5 px-3 py-1 text-xs font-medium rounded-t-md border-t border-l border-r transition-colors ${
                      isActive
                        ? 'bg-background text-foreground border-b-background translate-y-[1px]'
                        : 'bg-muted/30 text-muted-foreground hover:bg-muted/50 border-transparent'
                    }`}
                  >
                    <span
                      className="inline-block w-2.5 h-2.5 rounded-full"
                      style={{ backgroundColor: branchColors[idx] }}
                    />
                    {label}
                  </button>
                );
              })}
            </div>
          )}

          {/* Split Tabs (train / test / X / y …) */}
          {tabNames.length > 1 && (
            <div className="flex items-center gap-1 px-2 pt-2 border-b bg-muted/5">
              <Layers className="w-3 h-3 text-muted-foreground mr-1" />
              {tabNames.map(name => (
                <button
                  key={name}
                  onClick={() => { setActiveTab(name); }}
                  className={`px-3 py-1 text-xs font-medium rounded-t-md border-t border-l border-r transition-colors ${
                    activeTab === name 
                      ? 'bg-background text-primary border-b-background translate-y-[1px]' 
                      : 'bg-muted/30 text-muted-foreground hover:bg-muted/50 border-transparent'
                  }`}
                >
                  {name}
                </button>
              ))}
            </div>
          )}

          {/* Merge advisories (sibling fan-in etc.) — engine-emitted.
              Collapsed by default to a one-line summary; click to expand
              full per-warning detail (inputs, overlap columns, winner). */}
          {mergeWarnings.length > 0 && (
            <div className="bg-amber-50 dark:bg-amber-950/20 border-b dark:border-amber-900/30">
              <button
                type="button"
                onClick={() => setMergeWarningsOpen((v) => !v)}
                className="w-full flex items-center gap-2 px-2 py-1.5 text-xs text-amber-900 dark:text-amber-200 hover:bg-amber-100/60 dark:hover:bg-amber-900/30 transition-colors"
                aria-expanded={mergeWarningsOpen}
              >
                {mergeWarningsOpen ? (
                  <ChevronDown className="w-3.5 h-3.5 flex-shrink-0" />
                ) : (
                  <ChevronRight className="w-3.5 h-3.5 flex-shrink-0" />
                )}
                <AlertTriangle className="w-3.5 h-3.5 flex-shrink-0" />
                <span className="font-medium">
                  {mergeWarnings.length} merge advisor{mergeWarnings.length === 1 ? 'y' : 'ies'}
                </span>
                <span className="opacity-80 truncate">
                  — {mergeWarnings
                    .map((w) => nodeLabelMap[w.node_id] ?? w.node_id)
                    .slice(0, 3)
                    .join(', ')}
                  {mergeWarnings.length > 3 ? `, +${mergeWarnings.length - 3} more` : ''}
                </span>
              </button>
              {mergeWarningsOpen && (
                <div className="px-2 pb-2 space-y-1.5">
                  {mergeWarnings.map((w, idx) => {
                    // Row-wise merge dropped non-shared columns: render a
                    // simpler advisory (no inputs / overlap to show).
                    if (w.kind === 'row_concat_drop') {
                      const dropped = w.dropped_columns ?? [];
                      return (
                        <div key={idx} className="flex items-start gap-2 text-xs text-amber-900 dark:text-amber-200 pl-5">
                          <AlertTriangle className="w-3.5 h-3.5 mt-0.5 flex-shrink-0" />
                          <div className="flex-1">
                            <span className="font-medium">
                              {nodeLabelMap[w.node_id] ?? w.node_id}
                            </span>{' '}
                            row-wise merge{w.part ? ` (${w.part})` : ''} dropped{' '}
                            {dropped.length} non-shared column
                            {dropped.length === 1 ? '' : 's'}:{' '}
                            <span className="font-mono bg-amber-100 dark:bg-amber-900/40 px-1 rounded">
                              {dropped.slice(0, 6).join(', ')}
                              {dropped.length > 6 ? `, +${dropped.length - 6} more` : ''}
                            </span>
                            . Only columns present in every input are kept when row counts differ.
                          </div>
                        </div>
                      );
                    }
                    const inputs = w.inputs ?? [];
                    const inputLabels = inputs.map((i) => nodeLabelMap[i] ?? i);
                    const winner = w.winner_input
                      ? (nodeLabelMap[w.winner_input] ?? w.winner_input)
                      : inputLabels[inputLabels.length - 1];
                    const overlap = w.overlap_columns ?? [];
                    const canAutoChain = overlap.length > 0 && inputs.length >= 2;
                    return (
                      <div key={idx} className="flex items-start gap-2 text-xs text-amber-900 dark:text-amber-200 pl-5">
                        <AlertTriangle className="w-3.5 h-3.5 mt-0.5 flex-shrink-0" />
                        <div className="flex-1">
                          <span className="font-medium">
                            {nodeLabelMap[w.node_id] ?? w.node_id}
                          </span>{' '}
                          merges {inputs.length} parallel branches:{' '}
                          {inputLabels.map((label, i) => (
                            <span key={i}>
                              <span className="font-mono bg-amber-100 dark:bg-amber-900/40 px-1 rounded">
                                {label}
                              </span>
                              {i < inputLabels.length - 1 && ' + '}
                            </span>
                          ))}
                          .{' '}
                          {overlap.length > 0 ? (
                            <>
                              {overlap.length} overlapping column
                              {overlap.length === 1 ? '' : 's'}{' '}
                              (<span className="font-mono">
                                {overlap.slice(0, 4).join(', ')}
                                {overlap.length > 4 ? `, +${overlap.length - 4} more` : ''}
                              </span>){' '}
                              take values from{' '}
                              <span className="font-mono font-semibold">{winner}</span>;
                              unique columns from the others are kept as-is.
                            </>
                          ) : (
                            <>
                              No column overlap — all columns from all branches are kept.
                            </>
                          )}{' '}
                          For sequential application, chain them instead.
                          {canAutoChain && (
                            <div className="mt-1.5">
                              <button
                                type="button"
                                onClick={() => {
                                  const consumerLabel = nodeLabelMap[w.node_id] ?? w.node_id;
                                  const chainStr = [...inputLabels, consumerLabel].join(' → ');
                                  const ok = window.confirm(
                                    `Rewire as a linear chain?\n\n${chainStr}\n\nUse Ctrl+Z to undo.`
                                  );
                                  if (!ok) return;
                                  const success = chainSiblings(w.node_id, inputs);
                                  if (!success) {
                                    window.alert('Auto-chain failed. Re-run preview and try again.');
                                  }
                                }}
                                className="inline-flex items-center gap-1 px-2 py-0.5 text-[11px] font-medium rounded border border-amber-400 dark:border-amber-600 bg-amber-100 dark:bg-amber-900/40 hover:bg-amber-200 dark:hover:bg-amber-900/60 text-amber-900 dark:text-amber-100 transition-colors"
                                title="Rewire fan-in into a linear chain (no fan-in, no overwrite)"
                              >
                                <Wand2 className="w-3 h-3" />
                                Chain instead
                              </button>
                            </div>
                          )}
                        </div>
                      </div>
                    );
                  })}
                </div>
              )}
            </div>
          )}

          {/* Signals / Warnings */}
          {applied_steps.length > 0 && executionResult.status !== 'failed' && (
             <div className="p-2 bg-blue-50 dark:bg-blue-950/20 border-b dark:border-blue-900/30 flex gap-2 overflow-x-auto">
                {applied_steps.map((step: string, idx: number) => (
                  <div key={idx} className="text-xs text-blue-800 dark:text-blue-200 bg-blue-100 dark:bg-blue-900/40 px-2 py-1 rounded border border-blue-200 dark:border-blue-800 whitespace-nowrap">
                    {nodeLabelMap[step] ?? step}
                  </div>
                ))}
             </div>
          )}

          {/* Data Table */}
          <div className="flex-1 overflow-auto">
            <table className="w-full text-sm text-left border-collapse">
              <thead className="text-xs text-muted-foreground uppercase bg-muted sticky top-0 z-10 shadow-sm">
                <tr>
                  {columns.map((col) => (
                    <th key={col} className="px-4 py-2 font-medium border-b whitespace-nowrap">
                      {col}
                    </th>
                  ))}
                </tr>
              </thead>
              <tbody>
                {currentRows.map((row: unknown, idx: number) => (
                  <tr key={idx} className="border-b hover:bg-muted/10">
                    {columns.map((col) => (
                      <td key={`${idx}-${col}`} className="px-4 py-2 whitespace-nowrap font-mono text-xs">
                        {(row as Record<string, unknown>)[col] !== null ? String((row as Record<string, unknown>)[col]) : <span className="text-muted-foreground italic">null</span>}
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
            {currentRows.length === 0 && (
              <div className="flex items-center justify-center h-32 text-muted-foreground text-sm">
                No preview data available {activeTab ? `for ${activeTab}` : ''}
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
};

